            tube_count[i] = sum(1 for x in tube if x == color)

        for i, tube in enumerate(tubes):
            if tube_count[i] == 3:
                continue
            elif tube_count[i] == 2:
                top_ball, _ = get_top_ball(tube)
                if top_ball != color:
                    for j, other_tube in enumerate(tubes):
                        if tube_count[j] == 1 and get_top_ball(other_tube)[0] == color:
                            make_move(tubes, j, i, moves)
                            tube_count[i] += 1
                            tube_count[j] -= 1
                            break
            elif tube_count[i] == 1:
                for j, other_tube in enumerate(tubes):
                    if tube_count[j] == 2 and get_top_ball(other_tube)[0] == color:
                        make_move(tubes, i, j, moves)
                        tube_count[i] -= 1
                        tube_count[j] += 1
                        break
            else:
                for j, other_tube in enumerate(tubes):
                    if tube_count[j] == 1 and get_top_ball(other_tube)[0] == color:
                        make_move(tubes, j, i, moves)
                        tube_count[i] += 1
                        tube_count[j] -= 1
                        break
                for j, other_tube in enumerate(tubes):
                    if tube_count[j] == 1 and get_top_ball(other_tube)[0] == color:
                        make_move(tubes, j, i, moves)
                        tube_count[i] += 1
                        tube_count[j] -= 1
                        break

    # Clean up tubes with single color
    for i, tube in enumerate(tubes):
        top_ball, idx = get_top_ball(tube)
        if idx != -1 and tube[0] == tube[1] == tube[2]:
            continue
        else:
            if idx != -1:
                for j, other_tube in enumerate(tubes):
                    if i != j and other_tube[2] == 0:
                        make_move(tubes, i, j, moves)

    # Move remaining balls to empty tubes
    for i, tube in enumerate(tubes):
        top_ball, idx = get_top_ball(tube)
        if idx != -1:
            for j, other_tube in enumerate(tubes):
                if i != j and other_tube[0] == other_tube[1] == other_tube[2]:
                    make_move(tubes, i, j, moves)
                    break

    return moves

def main():
    n, tubes = read_input()
    moves = solve(n, tubes)
    print(len(moves))
    for move in moves:
        print(*move)

if __name__ == "__main__":
