            return False
    return True

def get_top_ball(tube):
    for i in range(2, -1, -1):
        if tube[i] != 0:
            return tube[i], i
    return 0, -1

def make_move(tubes, u, v, moves):
    top_ball, idx = get_top_ball(tubes[u])
    tubes[u][idx] = 0
    for i in range(3):
        if tubes[v][i] == 0:
            tubes[v][i] = top_ball
            moves.append((u + 1, v + 1))
