    for i in range(n + 1):
        tube = tubes[i]
        if tube[0] == tube[1] == tube[2]:
            tube_status[i] = 3
        elif tube[0] == tube[1]:
            tube_status[i] = 2
        elif tube[0] != 0:
            tube_status[i] = 1
        else:
            tube_status[i] = 0

    color_tube = [[] for _ in range(n + 1)]
    for i in range(n + 1):
        for j in range(3):
            if tubes[i][j] != 0:
                color_tube[tubes[i][j]].append((i, j))

    for color in range(1, n + 1):
        while True:
            positions = color_tube[color]
            if len(positions) == 0:
                break
            tube1, level1 = positions[0]
            tube2, level2 = positions[1]
            tube3, level3 = positions[2]
            if tube1 == tube2 == tube3:
                break
            top_tube = -1
            top_level = -1
            for tube, level in positions:
                if level > top_level:
                    top_tube = tube
                    top_level = level
            top_color = tubes[top_tube][top_level]
            if tube_status[top_tube] == 1:
                for dest in range(n + 1):
                    if dest != top_tube and tube_status[dest] < 3:
                        moves.append((top_tube + 1, dest + 1))
                        tube_status[top_tube] -= 1
                        tube_status[dest] += 1
                        tubes[dest][tube_status[dest] - 1] = top_color
