import sys
from collections import deque

def hilbert(x, y, n):
    if n == 0:
        return 0
    n -= 1
    l = 1 << n
    h = l // 2
    rx, ry = x, y
    if y < h:
        rx, ry = hilbert(x, y, n)
        t = rx
        rx = l - 1 - ry
        ry = t
    elif x < h:
        ry = l - 1 - (y - h)
        rx = hilbert(x, ry, n)
    elif x < l and y < l:
        rx = hilbert(x - h, y - h, n)
        rx += l
        ry = hilbert(y - h, x - h, n)
        ry += l
    else:
        rx = hilbert(y - h, x - l, n)
        rx += l
        ry = hilbert(x - l, y - l, n)
        ry += l
    return rx, ry

def is_wall(x1, y1, x2, y2, n):
    rx1, ry1 = hilbert(x1, y1, n)
    rx2, ry2 = hilbert(x2, y2, n)
    if abs(rx1 - rx2) + abs(ry1 - ry2) != 1:
        return True
    if rx1 > rx2:
        rx1, rx2 = rx2, rx1
    if ry1 > ry2:
        ry1, ry2 = ry2, ry1
    if rx1 == rx2:
        px, py = rx1, ry1
    else:
        px, py = rx1 + 1, ry1
    if px % 2 == 0 and py % 2 == 0:
        return True
    if px % 2 == 1 and py % 2 == 1:
        return True
    return False

def bfs(x, y, n, tx, ty):
    queue = deque([(x, y, 0)])
    visited = set([(x, y)])
    while queue:
        x, y, dist = queue.popleft()
        if (x, y) == (tx, ty):
            return dist
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) in visited:
                continue
            if is_wall(x, y, nx, ny, n):
                continue
            queue.append((nx, ny, dist + 1))
            visited.add((nx, ny))

def main():
    input = sys.stdin.readline
    k = int(input())
    for _ in range(k):
        n, x1, y1, x2, y2 = map(int, input().split())
        print(bfs(x1, y1, n, x2, y2))

if __name__ == '__main__':
