import sys
from collections import deque

def hilbert(x, y, n):
    if n == 0:
        return 0
    n -= 1
    l = 1 << n
    if x >= 0 and x < l and y >= 0 and y < l:
        return hilbert(y, x, n)
    elif x >= 0 and x < l and y >= l and y < (l << 1):
        return l * l + hilbert(x, y - l, n)
    elif x >= l and x < (l << 1) and y >= l and y < (l << 1):
        return (l * l << 1) + hilbert(x - l, y - l, n)
    elif x >= l and x < (l << 1) and y >= 0 and y < l:
        return (l * l << 2) + hilbert(l - 1 - (y), x - l, n)
    else:
        return (l * l << 1) - 1 - hilbert(l - 1 - (x), l - 1 - (y), n)

def is_wall(x1, y1, x2, y2, n):
    if abs(x1 - x2) + abs(y1 - y2) != 1:
        return True
    px, py = (x1 + x2) / 2, (y1 + y2) / 2
    h1, h2 = hilbert(x1, y1, n), hilbert(x2, y2, n)
    hp = hilbert(px, py, n)
    if h1 > h2:
        h1, h2 = h2, h1
    return h1 <= hp <= h2

def bfs(x, y, n, visited, queue):
    visited.add((x, y))
    queue.append((x, y))
    while queue:
        x, y = queue.popleft()
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in visited and not is_wall(x, y, nx, ny, n):
                visited.add((nx, ny))
                queue.append((nx, ny))

def main():
    input = sys.stdin.readline
    k = int(input())
    for _ in range(k):
        n, x1, y1, x2, y2 = map(int, input().split())
        visited = set()
        queue = deque()
        bfs(x1, y1, n, visited, queue)
        if (x2, y2) in visited:
            print(abs(x1 - x2) + abs(y1 - y2))
        else:
            queue = deque([(x1, y1, 0)])
            visited = set([(x1, y1)])
            while queue:
                x, y, d = queue.popleft()
                for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
                    nx, ny = x + dx, y + dy
                    if (nx, ny) not in visited and not is_wall(x, y, nx, ny, n):
                        if nx == x2 and ny == y2:
                            print(d + 1 + abs(x1 - x2) + abs(y1 - y2))
                            break
                        visited.add((nx, ny))
                        queue.append((nx, ny, d + 1))
                else:
                    continue
                break

