def is_valid(tube):
    """Check if a tube is in a valid state."""
    if tube[0] == 0:
        return True
    return tube[0] == tube[1] == tube[2] and tube[0] != 0

def get_top_color(tube):
    """Get the color of the top ball in a tube."""
    for color in reversed(tube):
        if color != 0:
            return color
    return 0

def get_top_index(tube):
    """Get the index of the top ball in a tube."""
    for i, color in enumerate(reversed(tube)):
        if color != 0:
            return 3 - i - 1
    return -1

def make_move(tubes, u, v):
    """Make a move by transferring the top ball from tube u to tube v."""
    top_index_u = get_top_index(tubes[u])
    top_index_v = get_top_index(tubes[v])
    tubes[v][top_index_v + 1] = tubes[u][top_index_u]
    tubes[u][top_index_u] = 0

def main():
    n = int(input())
    tubes = []
    for _ in range(n + 1):
        tube = list(map(int, input().split()))
        tubes.append(tube)

    moves = []
    for _ in range(20 * n):
        valid = all(is_valid(tube) for tube in tubes)
        if valid:
            break

        for u in range(n + 1):
            if is_valid(tubes[u]):
                continue
            top_color_u = get_top_color(tubes[u])
            for v in range(n + 1):
                if u == v:
                    continue
                top_index_v = get_top_index(tubes[v])
                if top_index_v == 2:
                    continue
                if top_index_v == -1 or tubes[v][top_index_v] == top_color_u:
                    make_move(tubes, u, v)
                    moves.append((u + 1, v + 1))
                    break

    print(len(moves))
    for u, v in moves:
        print(u, v)

