import sys

class SegmentTree:
    def __init__(self, n):
        self.n = n
        self.tree = [{} for _ in range(4 * n)]

    def update(self, node, start, end, idx, val, delta):
        if start == end:
            if val in self.tree[node]:
                self.tree[node][val] += delta
            else:
                self.tree[node][val] = delta
            return
        mid = (start + end) // 2
        if idx <= mid:
            self.update(2 * node, start, mid, idx, val, delta)
        else:
            self.update(2 * node + 1, mid + 1, end, idx, val, delta)
        self.tree[node] = self.merge(self.tree[2 * node], self.tree[2 * node + 1])

    def query(self, node, start, end, l, r):
        if start > r or end < l:
            return {}
        if l <= start and end <= r:
            return self.tree[node]
        mid = (start + end) // 2
        left = self.query(2 * node, start, mid, l, r)
        right = self.query(2 * node + 1, mid + 1, end, l, r)
        return self.merge(left, right)

    def merge(self, left, right):
        result = left.copy()
        for key, value in right.items():
            if key in result:
                result[key] += value
            else:
                result[key] = value
        return result

def main():
    n = int(sys.stdin.readline().strip())
    nums = list(map(int, sys.stdin.readline().strip().split()))
    seg_tree = SegmentTree(n)

    for i, num in enumerate(nums):
        seg_tree.update(1, 0, n - 1, i, num, 1)

    stack = [(0, n - 1)]
    while stack:
        start, end = stack.pop()
        query_result = seg_tree.query(1, 0, n - 1, start, end)
        sorted_powers = sorted(query_result.keys())
        for power in sorted_powers:
            count = query_result[power]
            if count >= 2:
                new_power = power * 2
                for i in range(start, end + 1):
                    if seg_tree.query(1, 0, n - 1, i, i)[power] == 1:
                        seg_tree.update(1, 0, n - 1, i, power, -1)
                        seg_tree.update(1, 0, n - 1, i, new_power, 1)
                if start != end:
                    stack.append((start, end))
                break
        else:
            max_power = max(query_result.keys())
            if query_result[max_power] == 1 and start != end:
                for i in range(start, end + 1):
                    if seg_tree.query(1, 0, n - 1, i, i)[max_power] == 1:
                        seg_tree.update(1, 0, n - 1, i, max_power, -1)
                        break
                stack.append((start, end - 1))
                stack.append((start + 1, end))

    final_result = seg_tree.query(1, 0, n - 1, 0, n - 1)
    max_power = max(final_result.keys())
    print(max_power)

