def read_input():
    n = int(input().strip())
    tubes = []
    for _ in range(n + 1):
        tube = list(map(int, input().strip().split()))
        tubes.append(tube)
    return n, tubes

def is_color_tubes_state(tubes):
    for tube in tubes:
        if sum(1 for ball in tube if ball != 0) == 3 and len(set(tube)) != 1:
            return False
    return True

def get_top_ball(tube):
    for ball in reversed(tube):
        if ball != 0:
            return ball
    return 0

def get_num_balls(tube):
    return sum(1 for ball in tube if ball != 0)

def is_valid_move(tubes, u, v):
    top_ball_u = get_top_ball(tubes[u])
    num_balls_v = get_num_balls(tubes[v])
    if top_ball_u == 0 or num_balls_v == 3:
        return False
    return True

def make_move(tubes, u, v):
    top_ball_u = get_top_ball(tubes[u])
    tubes[u][tubes[u].index(top_ball_u)] = 0
    tubes[v][2 - get_num_balls(tubes[v])] = top_ball_u

def evaluate_move(tubes, u, v):
    score = 0
    top_ball_u = get_top_ball(tubes[u])
    top_ball_v = get_top_ball(tubes[v])
    if top_ball_v == top_ball_u:
        score += 10
    if get_num_balls(tubes[v]) == 2 and tubes[v][0] == tubes[v][1] == top_ball_u:
        score += 100
    if get_num_balls(tubes[u]) == 1:
        score += 1
    return score

def select_best_move(tubes, n):
    best_score = -1
    best_move = None
    for u in range(n + 1):
        for v in range(n + 1):
            if u == v:
                continue
            if is_valid_move(tubes, u, v):
                score = evaluate_move(tubes, u, v)
                if score > best_score:
                    best_score = score
                    best_move = (u, v)
    return best_move

def solve(n, tubes):
    moves = []
    while not is_color_tubes_state(tubes) and len(moves) < 20 * n:
        best_move = select_best_move(tubes, n)
        if best_move is None:
            break
        u, v = best_move
        make_move(tubes, u, v)
        moves.append((u + 1, v + 1))
    return moves

def print_output(moves):
    print(len(moves))
    for move in moves:
        print(*move)

def main():
    n, tubes = read_input()
    moves = solve(n, tubes)
    print_output(moves)

if __name__ == "__main__":
    main()
