import heapq
import sys

def dijkstra(s, t, blades):
    # Create a priority queue to store nodes to be processed
    queue = [(0, s)]  # (time, size)
    visited = set()

    while queue:
        time, size = heapq.heappop(queue)
        if size in visited:
            continue
        visited.add(size)

        if size <= t:
            return time

        # Apply blades
        for m, h in blades:
            if size <= m:
                new_size = size / 2
                new_time = time + h
                heapq.heappush(queue, (new_time, new_size))

        # Try to reach a size that is just below a blade's maximum capacity
        for m, h in blades:
            if size > m and m not in visited:
                new_time = time + h * (sys.float_info.max if size == 0 else (sys.float_info.max if m == 0 else (math.log(size) - math.log(m)) / math.log(2)))
                heapq.heappush(queue, (new_time, m))

    return float('inf')

import math

def main():
