        blades = []
        for _ in range(n):
            m, h = map(int, sys.stdin.readline().split())
            blades.append((m, h * math.log(2)))

        min_time = dijkstra(s, t, blades)
        if min_time == float('inf'):
            print(-1)
        else:
            print(min_time)
    except Exception as e:
        # In a real application, you might want to log this error
        pass

