def hilbert(x, y, n, direction):
    if n == 0:
        return
    half_size = 1 << (n - 1)
    if direction == 0:  # right
        if y < 0:
            hilbert(-y, x, n - 1, 3)
        elif x >= half_size:
            hilbert(x - half_size, y, n - 1, 0)
            print('F', end='')
        elif y >= half_size:
            hilbert(x, y - half_size, n - 1, 0)
            print('R', end='')
        else:
