    elif direction == 1:  # up
        if x < 0:
            hilbert(-x, -y, n - 1, 0)
        elif y >= half_size:
            hilbert(x, y - half_size, n - 1, 1)
            print('F', end='')
        elif x >= half_size:
            hilbert(x - half_size, y, n - 1, 1)
            print('R', end='')
        else:
            hilbert(y, x, n - 1, 2)
            print('F', end='')
    elif direction == 2:  # left
        if y >= half_size:
            hilbert(half_size - 1 - y, x, n - 1, 1)
        elif x < half_size:
            hilbert(x, y - half_size, n - 1, 2)
            print('F', end='')
        elif y < half_size:
            hilbert(x - half_size, y, n - 1, 2)
            print('L', end='')
        else:
            hilbert(y - half_size, x - half_size, n - 1, 3)
            print('F', end='')
    elif direction == 3:  # down
        if x >= half_size:
            hilbert(half_size - 1 - x, -y, n - 1, 2)
        elif y < half_size:
            hilbert(x - half_size, y, n - 1, 3)
            print('F', end='')
        elif x < half_size:
            hilbert(x, y - half_size, n - 1, 3)
            print('L', end='')
        else:
            hilbert(half_size - 1 - y, x - half_size, n - 1, 0)
            print('F', end='')

def has_hedge(x1, y1, x2, y2, n):
    size = 1 << n
    if x1 < 0 or x1 >= size or y1 < 0 or y1 >= size or x2 < 0 or x2 >= size or y2 < 0 or y2 >= size:
        return True
    if abs(x1 - x2) + abs(y1 - y2) != 1:
        return True
    dir1 = get_direction(x1, y1, n)
    dir2 = get_direction(x2, y2, n)
    return dir1 != dir2

def get_direction(x, y, n):
    if n == 0:
        return 0
    half_size = 1 << (n - 1)
    if x < half_size and y < half_size:
        return (get_direction(y, x, n - 1) + 3) % 4
    elif x < half_size and y >= half_size:
        return get_direction(x, y - half_size, n - 1)
    elif x >= half_size and y < half_size:
        return (get_direction(x - half_size, y, n - 1) + 1) % 4
    else:
        return get_direction(y - half_size, x - half_size, n - 1)

def bfs(n, x1, y1, x2, y2):
    size = 1 << n
    if x1 < 0 or x1 >= size or y1 < 0 or y1 >= size or x2 < 0 or x2 >= size or y2 < 0 or y2 >= size:
        return -1
    queue = deque([(x1, y1, 0)])
    visited = set((x1, y1))
    while queue:
        x, y, dist = queue.popleft()
        if x == x2 and y == y2:
            return dist
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in visited and not has_hedge(x, y, nx, ny, n):
                queue.append((nx, ny, dist + 1))
                visited.add((nx, ny))
    return -1

def main():
