def slide_count(N, C, w):
    prefix_sum = [0] * (N + 1)
    for i in range(N):
        prefix_sum[i + 1] = prefix_sum[i] + w[i]

    count = [0] * N
    s, e = 0, 0

    while s < N:
        while e < N and prefix_sum[e + 1] - prefix_sum[s] <= C:
            e += 1
        # For each window (s, e), increment the count of elements within it
        if s <= e:
            count[s] += 1
            if e + 1 < N:
                count[e + 1] -= 1
        s += 1

    # Compute the final count by accumulating the differences
    for i in range(1, N):
        count[i] += count[i - 1]

    return count

