from collections import deque

def hilbert(x, y, n, direction):
    """Compute the Hilbert curve coordinates"""
    if n == 0:
        return 0
    size = 1 << (n - 1)
    if direction == 'A':
        if y < size:
            return hilbert(y, x, n - 1, 'B')
        else:
            return size * size + hilbert(x, y - size, n - 1, 'A')
    elif direction == 'B':
        if x < size:
            return size * size + hilbert(x, y, n - 1, 'B')
        else:
            return 2 * size * size + hilbert(x - size, y, n - 1, 'B')
    elif direction == 'L':
        return hilbert(x, y, n - 1, 'A')
    elif direction == 'R':
        return 3 * size * size + hilbert(size - 1 - y, size - 1 - x, n - 1, 'B')
    elif direction == 'F':
        if x < size:
            if y < size:
                return hilbert(y, x, n - 1, 'B')
            else:
                return size * size + hilbert(x, y - size, n - 1, 'A')
        else:
            if y < size:
                return 3 * size * size + hilbert(size - 1 - y, size - 1 - (x - size), n - 1, 'B')
            else:
                return 2 * size * size + hilbert(x - size, y - size, n - 1, 'B')

def is_connected(x1, y1, x2, y2, n):
    """Check if two cells are connected"""
    d1 = hilbert(x1, y1, n, 'A')
    d2 = hilbert(x2, y2, n, 'A')
    if abs(x1 - x2) + abs(y1 - y2) != 1:
        return False
    return (d1 // (1 << (2 * n - 2)) == d2 // (1 << (2 * n - 2)))

def bfs(x1, y1, x2, y2, n):
    """Perform BFS to find the shortest distance"""
    queue = deque([(x1, y1, 0)])
    visited = set((x1, y1))
    while queue:
        x, y, dist = queue.popleft()
        if (x, y) == (x2, y2):
            return dist
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in visited and is_connected(x, y, nx, ny, n):
                queue.append((nx, ny, dist + 1))
                visited.add((nx, ny))

