    robot1_dir, robot2_dir = 'NESW'.index(robot1_dir), 'NESW'.index(robot2_dir)

    num_hwalls, *hwalls = map(int, input().split())
    hwall_set = set((hwalls[i], hwalls[i+1]) for i in range(0, 2*num_hwalls, 2))

    num_vwalls, *vwalls = map(int, input().split())
    vwall_set = set((vwalls[i], vwalls[i+1]) for i in range(0, 2*num_vwalls, 2))

    min_forward, min_bumps = iddfs((robot1_col, robot1_row, robot1_dir), (robot2_col, robot2_row, robot2_dir), 
                                   cols, rows, exit_col, hwall_set, vwall_set)
    print(min_forward, min_bumps)

def iddfs(robot1, robot2, cols, rows, exit_col, hwall_set, vwall_set):
    for max_depth in range(1, cols * rows + 1):
        result = dls(robot1, robot2, cols, rows, exit_col, hwall_set, vwall_set, max_depth)
        if result is not None:
            return result

def dls(robot1, robot2, cols, rows, exit_col, hwall_set, vwall_set, max_depth):
    queue = deque([(robot1, robot2, 0, 0)])
    visited = set()
    min_forward = float('inf')
    min_bumps = float('inf')

    while queue:
        (r1_col, r1_row, r1_dir), (r2_col, r2_row, r2_dir), forward, bumps = queue.popleft()
        state = ((r1_col, r1_row, r1_dir), (r2_col, r2_row, r2_dir))

        if state in visited:
            continue
        visited.add(state)

        if (r1_col == exit_col and r1_row == 1) or (r2_col == exit_col and r2_row == 1):
            if forward < min_forward or (forward == min_forward and bumps < min_bumps):
                min_forward = forward
                min_bumps = bumps

        if forward < max_depth:
            new_r1_col, new_r1_row, r1_bump = move(r1_col, r1_row, r1_dir, cols, rows, exit_col, hwall_set, vwall_set)
            new_r2_col, new_r2_row, r2_bump = move(r2_col, r2_row, r2_dir, cols, rows, exit_col, hwall_set, vwall_set)
            new_bumps = bumps + r1_bump + r2_bump

            if (new_r1_col, new_r1_row) != (new_r2_col, new_r2_row) or ((new_r1_col, new_r1_row) == (exit_col, 1) or (new_r2_col, new_r2_row) == (exit_col, 1)):
                queue.append(((new_r1_col, new_r1_row, r1_dir), (new_r2_col, new_r2_row, r2_dir), forward + 1, new_bumps))

            new_r1_dir = (r1_dir + 1) % 4
            new_r2_dir = (r2_dir + 1) % 4
            queue.append(((r1_col, r1_row, new_r1_dir), (r2_col, r2_row, new_r2_dir), forward, bumps))

            new_r1_dir = (r1_dir - 1) % 4
            new_r2_dir = (r2_dir - 1) % 4
            queue.append(((r1_col, r1_row, new_r1_dir), (r2_col, r2_row, new_r2_dir), forward, bumps))

    if min_forward != float('inf'):
        return min_forward, min_bumps
    else:
        return None

def move(col, row, direction, cols, rows, exit_col, hwall_set, vwall_set):
    d_col = [0, 1, 0, -1][direction]
    d_row = [-1, 0, 1, 0][direction]
    new_col, new_row = col + d_col, row + d_row

    if 1 <= new_col <= cols and 1 <= new_row <= rows:
        if d_col == 1 and (col, row) in vwall_set:
            return col, row, 1
        elif d_col == -1 and (new_col, row) in vwall_set:
            return col, row, 1
        elif d_row == 1 and (col, new_row-1) in hwall_set:
            return col, row, 1
        elif d_row == -1 and (col, row) in hwall_set:
            return col, row, 1
        else:
            return new_col, new_row, 0
    elif new_col == exit_col and new_row == 0:
        return new_col, new_row, 0
    else:
        return col, row, 0

