from collections import deque

def rot(n, x, y, rx, ry):
    if ry == 0:
        if rx == 1:
            x, y = n - 1 - y, x
            rx, ry = 0, 1
        return x, y, rx, ry
    if rx == 0:
        if ry == -1:
            x, y = n - 1 - y, x
            rx, ry = 1, 0
        return x, y, rx, ry
    x, y = y, n - 1 - x
    return x, y, rx, ry

def dxy(n, d):
    if d == 0:
        return 0, 1
    if d == 1:
        return 1, 0
    if d == 2:
        return 0, -1
    if d == 3:
        return -1, 0

def hedge(n, x, y):
    rx, ry = 0, 1
    lx, ly = 0, 0
    s = 1
    while s <= n:
        x, y, rx, ry = rot(s, x, y, rx, ry)
        lx += s * rx
        ly += s * ry
        if rx == 0 and ry == 1:
            if x >= s:
                return True
            x -= s
        elif rx == 1 and ry == 0:
            if y < 0:
                return True
            y += s
        elif rx == 0 and ry == -1:
            if x < 0:
                return True
            x += s
        elif rx == -1 and ry == 0:
            if y >= s:
                return True
            y -= s
        s *= 2
    dx, dy = dxy(s, (lx + ly + 1) % 4)
    return lx + dx >= ly + dy

def bfs(n, x1, y1, x2, y2):
    if (x1, y1) == (x2, y2):
        return 0
    q = deque([(x1, y1, 0)])
    vis = set([(x1, y1)])
    while q:
