from collections import deque

def hilbert(x, y, n):
    """Compute the Hilbert curve value at (x, y) for order n."""
    v = 0
    for i in range(n, 0, -1):
        m = 1 << (i - 1)
        q = 0
        if x & m:
            q |= 1
        if y & m:
            q |= 2
        v = (v << 2) | q
    return v

def is_hedge(x1, y1, x2, y2, n):
    """Check if there's a hedge between (x1, y1) and (x2, y2) for order n."""
    if abs(x1 - x2) + abs(y1 - y2) != 1:
        return True  # Hedge if not adjacent
    if n == 0:
        return False  # No hedge at order 0
    m = 1 << (n - 1)
    h1 = hilbert(min(x1, x2), min(y1, y2), n)
    h2 = hilbert(x1, y1, n)
    h3 = hilbert(x2, y2, n)
    if h1 == 0:
        if (x1 + y1 == x2 + y2) and ((x1 & m) == (y1 & m) == m):
            return True
        if (x1 + y1 != x2 + y2) and ((x1 & m) != (y1 & m)):
            return True
    elif h1 == 1:
        if (x1 + y1 == x2 + y2) and (y1 & m):
            return True
        if (x1 + y1 != x2 + y2) and ((x1 & m) == (y1 & m) == 0):
            return True
    elif h1 == 2:
        if (x1 + y1 == x2 + y2) and ((x1 & m) == 0):
            return True
        if (x1 + y1 != x2 + y2) and ((x1 & m) == (y1 & m) == m):
            return True
    elif h1 == 3:
        if (x1 + y1 == x2 + y2) and ((x1 & m) == (y1 & m) == 0):
            return True
        if (x1 + y1 != x2 + y2) and (y1 & m == 0):
            return True
    return False

def bfs(x1, y1, x2, y2, n, memo):
    """Perform BFS to find the shortest distance between (x1, y1) and (x2, y2)."""
    queue = deque([(x1, y1, 0)])
    visited = set([(x1, y1)])
    while queue:
        x, y, d = queue.popleft()
        if (x, y) == (x2, y2):
            return d
        for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in visited and not is_hedge(x, y, nx, ny, n):
                queue.append((nx, ny, d + 1))
                visited.add((nx, ny))
    return -1  # No path found

